def update_parent_recursively(task):
    # defines the start/end dates for the parent tasks from their children
    if not (parent := task.parent_id):
        return
    siblings = env['project.task'].search([('parent_id', '=', parent.id)])
    vals = {}
    # --- ROLL-UP TIME ---
    vals['allocated_hours'] = sum(siblings.mapped('allocated_hours') or [0.0])
    # --- ROLL-UP DATES ---
    starts = [c.planned_date_begin for c in siblings | parent if c.planned_date_begin]
    ends = [c.date_deadline for c in siblings | parent if c.date_deadline]
    if starts:
        vals['planned_date_begin'] = min(starts)
    if ends:
        vals['date_deadline'] = max(ends)
    parent.with_context(skip_task_date_recomputation=True).write(vals)
    if parent.parent_id:
        update_parent_recursively(parent)

def slide_children(task, new_start, new_end, old_start, old_end):
    if new_start and old_start and new_end and old_end and (delta := new_start - old_start) == new_end - old_end:
        for c in task.child_ids.filtered(lambda c: c.planned_date_begin and c.date_deadline):
            c.with_context(skip_task_date_recomputation=True).write({'planned_date_begin': c.planned_date_begin + delta, 'date_deadline': c.date_deadline + delta})
            slide_children(c, new_start, new_end, old_start, old_end)
    else:
        for c in [c for c in task.child_ids if c.planned_date_begin == old_start]:
            c.write({'planned_date_begin': new_start, 'date_deadline': new_start + (c.date_deadline - c.planned_date_begin)})
            slide_children(c, new_start, new_end, old_start, old_end)
        for c in [c for c in task.child_ids if c.date_deadline == old_end]:
            c.with_context(skip_task_date_recomputation=True).write({'date_deadline': new_end, 'planned_date_begin': new_end - (c.date_deadline - c.planned_date_begin)})
            slide_children(c, new_start, new_end, old_start, old_end)


for record in records:
    # Query the DB directly to get the pre-changes values
    env.cr.execute("SELECT planned_date_begin, date_deadline FROM project_task WHERE id = %s", (record.id,))
    res = env.cr.fetchone()
    old_start_raw, old_end_raw = res[0:2] if res else (False, False)
    old_start = old_start_raw if isinstance(old_start_raw, datetime.datetime) else False
    old_end = old_end_raw if isinstance(old_end_raw, datetime.datetime) else False
    new_start, new_end = record.planned_date_begin, record.date_deadline

    if not env.context.get('skip_task_date_recomputation'):
        update_parent_recursively(record)
        slide_children(record, new_start, new_end, old_start, old_end)

for record in records:
    l1, l2, l3 = 0, 0, 0
    in_sub = False

    for sol in record.order_line.sorted('sequence'):
        new_item_number = False

        if not sol.parent_id:  # top-level row (product or section)
            l1 += 1; l2 = 0; l3 = 0

        if sol.display_type == 'line_section':
            l2 += 1; l3 = 0
            new_item_number = f"{l1}."
        elif sol.display_type == 'line_subsection' and (sol.name or '').strip():
            l3 += 1
            new_item_number = f"{l1}.{l2}."
        elif not sol.display_type:  # don't count notes
            if l3:
                new_item_number = f"{l1}.{l2}.{l3}."
                l3 += 1
            elif l2:
                new_item_number = f"{l1}.{l2}."
                l2 += 1
            else:
                new_item_number = f"{l1}."

        if sol.x_item_number != new_item_number:
            sol.write({'x_item_number': new_item_number})
